import classes from "./MainHeaderTab.module.css";
import { useContext, React } from "react";
import { AppContext } from "../../store/app-context";

const MainHeaderTab = (props) => {
  const ctx = useContext(AppContext);

  const setTabHandler = () => {
    ctx.setSelectedTab(props.title);
  };

  console.log("TABS RERENDER");

  return (
    <div className={classes["tab"]} onClick={setTabHandler}>
      {props.title}
    </div>
  );
};

export default MainHeaderTab;
